6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This entity implements a simple I2C-master (multi master capable)
11	
12	library ieee;
13	use ieee.std_logic_1164.all;
14	use ieee.numeric_std.all;
15	use ieee.math_real.all;
16	
17	use work.psi_common_math_pkg.all;
18	use work.psi_common_logic_pkg.all;
19	
20	------------------------------------------------------------------------------
21	-- Package for Interface Simplification
22	------------------------------------------------------------------------------
23	package psi_common_i2c_master_pkg is
24	  constant CMD_START    : std_logic_vector(2 downto 0) := "000";
25	  constant CMD_STOP     : std_logic_vector(2 downto 0) := "001";
26	  constant CMD_REPSTART : std_logic_vector(2 downto 0) := "010";
27	  constant CMD_SEND     : std_logic_vector(2 downto 0) := "011";
28	  constant CMD_REC      : std_logic_vector(2 downto 0) := "100";
29	end package;
30	
31	library ieee;
32	use ieee.std_logic_1164.all;
33	use ieee.numeric_std.all;
34	use ieee.math_real.all;
35	
36	use work.psi_common_math_pkg.all;
37	use work.psi_common_logic_pkg.all;
38	use work.psi_common_i2c_master_pkg.all;
39	
40	entity psi_common_i2c_master is
41	  generic(
42	          clock_frequency_g    : real    := 125.0e6;          -- in Hz, frequency system clock		
43	          i2c_frequency_g      : real    := 100.0e3;          -- in Hz, frequency I2C clock		
44	          bus_busy_timeout_g   : real    := 1.0e-3;           -- in sec	If *I2cScl* = '1' and *I2cSda* = '1' for this time in sec., the bus is regarded as free.
45	                                                              -- If the user does not provide any command for this time, the block automatically generates a stop-condition to release the bus.	
46	          cmd_timeout_g        : real    := 100.0e-6;         -- in sec		When the block is ready for the next command but the user does not provide a new command,
47	                                                              -- after this timeout the bus is releases (and TimeoutCmd is pulsed to inform the user).
48	          internal_tri_state_g : boolean := true;             -- True  => Use internal tri-state buffer i2c_scl and i2c_sda are used.
49	                                                              -- False => Use external tri-state buffer i2c_scl_x and i2c_sda_x are used.				
50	          disable_asserts_g    : boolean := false;            -- If true, the block does not print any messages during simulations
51	          rst_pol_g            : std_logic:= '1');            -- '1' active high, '0' active low
52	  port(   -- Control Signals
53	          clk_i          : in    std_logic;                   -- system clock
54	          rst_i          : in    std_logic;                   -- system reset
55	          -- Command Interface
56	          cmd_rdy_o      : out   std_logic;                   -- AXI-S handshaking signal for commande interface
57	          cmd_vld_i      : in    std_logic;                   -- AXI-S handshaking signal for command   interface  
58	          cmd_type_i     : in    std_logic_vector(2 downto 0);-- cst: "000" => Send start condition CMD_START 
59	                                                              --      "001" => Send stop condition CMD_STOP
60	                                                              --      "010" => Send repeated start condition  CMD_REPSTART
61	                                                              --      "011" => Send data  byte CMD_SEND 
62	                                                              --      "100" => Receive data byte  CMD_RECEIVE  
63	          cmd_dat_i      : in    std_logic_vector(7 downto 0);-- Input data to send only for CMD_SEND  resp. CmdType="011".
64	          cmd_ack_i      : in    std_logic;                   -- Acknowledge to send only for CMD_RECEIVE* resp. *CmdType="100"
65	          -- Response Interface
66	          rsp_vld_o      : out   std_logic;                   -- AXI-S handshaking signal for response interface  
67	          rsp_type_o     : out   std_logic_vector(2 downto 0);-- Type of the command that completed. See *CmdType* for details.
68	          rsp_dat_o      : out   std_logic_vector(7 downto 0);-- Received data (only for *CMD\_RECEIVE* resp.  *CmdType="100"*).
69	          rsp_ack_o      : out   std_logic;                   -- 1 => ACK received, 0 => NACK received 
70	          rsp_arb_lost_o : out   std_logic;                   -- The command failed because arbitration was lost
71	          rsp_seq_o      : out   std_logic;                   -- The command failed because of wrong command sequence(e.g. attempt to do a CMD_START in the middle of an ongoing transfer
72	          -- Status Interface
73	          bus_busy_o     : out   std_logic;                   -- I2C bus is busy (used by this master or another master)  
74	          timeout_cmd_o  : out   std_logic;                   -- Pulsed if the bus is released due to a timeout.
75	          -- I2c Interface with internal Tri-State 
76	          i2c_scl_io     : inout std_logic := 'Z';            -- SCL signal 
77	          i2c_sda_io     : inout std_logic := 'Z';            -- SDA signal
78	          -- I2c Interface with external Tri-State
79	          i2c_scl_i      : in    std_logic := '0';            -- SCL input signal 
80	          i2c_scl_o      : out   std_logic;                   -- SCL output signal 
81	          i2c_scl_t      : out   std_logic;                   -- SCL Tri-State signal (1 = tristated, 0 drive) 
82	          i2c_sda_i      : in    std_logic := '0';            -- SDA input signal 
83	          i2c_sda_o      : out   std_logic;                   -- SDA output signal
84	          i2c_sda_t      : out   std_logic);                  -- SDA Tri-State signal (1 = tristated, 0 drive)
85	end entity;
86	
87	architecture rtl of psi_common_i2c_master is
88	
89	  -- *** Constants ***
90	  constant BusyTimoutLimit_c    : integer := integer(clock_frequency_g * bus_busy_timeout_g) - 1;
91	  constant QuarterPeriodLimit_c : integer := integer(ceil(clock_frequency_g / i2c_frequency_g / 4.0)) - 1;
92	  constant CmdTimeoutLimit_c    : integer := integer(clock_frequency_g * cmd_timeout_g) - 1;
93	
94	  -- *** Types ***
95	  type Fsm_t is (BusIdle_s, BusBusy_s, MinIdle_s, Start1_s, Start2_s, WaitCmd_s, WaitLowCenter_s, Stop1_s, Stop2_s, Stop3_s, RepStart1_s,
96	                 DataBit1_s, DataBit2_s, DataBit3_s, DataBit4_s, ArbitLost_s);
97	
98	  -- *** Two Process Method ***
99	  type two_process_r is record
100	    bus_busy_o     : std_logic;
101	    cmd_rdy_o      : std_logic;
102	    SclLast        : std_logic;
103	    SdaLast        : std_logic;
104	    BusBusyToCnt   : unsigned(log2ceil(BusyTimoutLimit_c + 1) - 1 downto 0);
105	    TimeoutCmdCnt  : unsigned(log2ceil(CmdTimeoutLimit_c + 1) - 1 downto 0);
106	    QuartPeriodCnt : unsigned(log2ceil(QuarterPeriodLimit_c + 1) - 1 downto 0);
107	    QPeriodTick    : std_logic;
108	    CmdTypeLatch   : std_logic_vector(cmd_type_i'range);
109	    CmdAckLatch    : std_logic;
110	    Fsm            : Fsm_t;
111	    SclOut         : std_logic;
112	    SdaOut         : std_logic;
113	    rsp_vld_o      : std_logic;
114	    rsp_ack_o      : std_logic;
115	    rsp_seq_o      : std_logic;
116	    rsp_dat_o      : std_logic_vector(7 downto 0);
117	    rsp_arb_lost_o : std_logic;
118	    BitCnt         : unsigned(3 downto 0); -- 8 Data + 1 Ack = 9 = 4 bits
119	    ShReg          : std_logic_vector(8 downto 0);
120	    CmdTimeout     : std_logic;
121	    timeout_cmd_o  : std_logic;
122	  end record;
123	  signal r, r_next     : two_process_r;
124	  attribute dont_touch : string;
125	  attribute dont_touch of r : signal is "true"; -- Required to Fix Vivado 2018.2 Synthesis Bug! Is fixed in Vivado 2019.1 according to Xilinx.
126	
127	  -- Tri-state buffer muxing
128	  signal I2cScl_Input : std_logic;
129	  signal I2cSda_Input : std_logic;
130	  signal I2cScl_Sync  : std_logic;
131	  signal I2cSda_Sync  : std_logic;
132	
133	begin
134	
135	  --------------------------------------------------------------------------
136	  -- Combinatorial Proccess
137	  --------------------------------------------------------------------------
138	  p_comb : process(r, I2cScl_Sync, I2cSda_Sync, cmd_vld_i, cmd_type_i, cmd_dat_i, cmd_ack_i)
139	    variable v                                  : two_process_r;
140	    variable   SdaRe_v, SdaFe_v : std_logic;
141	    variable I2cStart_v, I2cStop_v              : std_logic;
142	  begin
143	    -- *** hold variables stable ***
144	    v := r;
145	
146	    -- *** Edge Detection ***
147	    --SclRe_v   := not r.SclLast and I2cScl_Sync;
148	    --SclFe_v   := r.SclLast and not I2cScl_Sync;
149	    SdaRe_v   := not r.SdaLast and I2cSda_Sync;
150	    SdaFe_v   := r.SdaLast and not I2cSda_Sync;
151	    v.SclLast := I2cScl_Sync;
152	    v.SdaLast := I2cSda_Sync;
153	
154	    -- *** Start/Stop Detection ***
155	    I2cStart_v := r.SclLast and I2cScl_Sync and SdaFe_v;
156	    I2cStop_v  := r.SclLast and I2cScl_Sync and SdaRe_v;
157	
158	    -- *** Quarter Period Counter ***
159	    -- The FSM may overwrite the counter in some cases!
160	    v.QPeriodTick := '0';
161	    if (r.Fsm = BusIdle_s) or (r.Fsm = BusBusy_s) then
162	      v.QuartPeriodCnt := (others => '0');
163	    elsif r.QuartPeriodCnt = QuarterPeriodLimit_c then
164	      v.QuartPeriodCnt := (others => '0');
165	      v.QPeriodTick    := '1';
166	    else
167	      v.QuartPeriodCnt := r.QuartPeriodCnt + 1;
168	    end if;
169	
170	    -- *** Command Timeout Detection ***
171	    if r.Fsm = WaitCmd_s then
172	      -- Timeout
173	      if r.TimeoutCmdCnt = CmdTimeoutLimit_c then
174	        v.CmdTimeout := '1';
175	      -- Count
176	      else
177	        v.TimeoutCmdCnt := r.TimeoutCmdCnt + 1;
178	      end if;
179	    -- In all states except waiting for command, reset the timer
180	    else
181	      v.TimeoutCmdCnt := (others => '0');
182	    end if;
183	
184	    -- *** Latch Command ***
185	    if (r.cmd_rdy_o = '1') and (cmd_vld_i = '1') then
186	      v.CmdTypeLatch := cmd_type_i;
187	      v.CmdAckLatch  := cmd_ack_i;
188	    end if;
189	
190	    -- *** Default Values ***
191	    v.rsp_vld_o      := '0';
192	    v.rsp_ack_o      := not r.ShReg(0);
193	    v.rsp_dat_o      := r.ShReg(8 downto 1);
194	    v.rsp_seq_o      := '0';
195	    v.rsp_arb_lost_o := '0';
196	    v.timeout_cmd_o  := '0';
197	    v.cmd_rdy_o      := '0';
198	
199	    -- *** FSM ***
200	    case r.Fsm is
201	
202	      -- **********************************************************************************************
203	      -- Bus Idle
204	      -- **********************************************************************************************
205	      when BusIdle_s =>
206	        -- Default Outputs
207	        v.cmd_rdy_o    := '1';
208	        v.BusBusyToCnt := (others => '0');
209	        v.SclOut       := '1';
210	        v.SdaOut       := '1';
211	        v.CmdTimeout   := '0';
212	
213	        -- Detect Bus Busy by Start Command
214	        if (r.cmd_rdy_o = '1') and (cmd_vld_i = '1') then
215	          -- Everyting else than START commands is ignored and an error is printed in this case
216	          assert (cmd_type_i = CMD_START) or disable_asserts_g
217	          report "###ERROR###: psi_common_i2c_master: In idle state, only CMD_START commands are allowed!"
218	          severity error;
219	          if cmd_type_i = CMD_START then
220	            v.Fsm          := Start1_s;
221	            v.cmd_rdy_o    := '0';
222	            v.CmdTypeLatch := cmd_type_i;
223	          else
224	            v.rsp_vld_o := '1';
225	            v.rsp_seq_o := '1';
226	          end if;
227	        -- Detect Busy from other master
228	        elsif (I2cScl_Sync = '0') or (I2cStart_v = '1') then
229	          v.Fsm       := BusBusy_s;
230	          v.cmd_rdy_o := '0';
231	        end if;
232	
233	      -- **********************************************************************************************
234	      -- Bus Busy by other master
235	      -- **********************************************************************************************
236	      when BusBusy_s =>
237	        -- Bus released
238	        if I2cStop_v = '1' then
239	          v.Fsm := MinIdle_s;
240	        end if;
241	        -- Timeout Handling
242	        if I2cScl_Sync = '0' then
243	          v.BusBusyToCnt := (others => '0');
244	        elsif r.BusBusyToCnt = BusyTimoutLimit_c then
245	          v.Fsm := BusIdle_s;
246	        else
247	          v.BusBusyToCnt := r.BusBusyToCnt + 1;
248	        end if;
249	
250	        v.SclOut := '1';
251	        v.SdaOut := '1';
252	
253	      -- Ensure that SDA stays low for at least half a clock period
254	      when MinIdle_s =>
255	        if r.QPeriodTick = '1' then
256	          v.Fsm := BusIdle_s;
257	        end if;
258	
259	        v.SclOut := '1';
260	        v.SdaOut := '1';
261	
262	      -- **********************************************************************************************
263	      -- Start Condition
264	      -- **********************************************************************************************
265	      -- State	BusBusy_s   Start1_s   Start2_s   WaitCmd_s
266	      --        __________________________________
267	      -- Scl ...                                  |___________ ...
268	      --        _______________________
269	      -- SDA ...                       |______________________ ...
270	      -- **********************************************************************************************
271	
272	      when Start1_s =>
273	        if r.QPeriodTick = '1' then
274	          v.Fsm := Start2_s;
275	        end if;
276	
277	        -- Handle Clock Stretching in case of a repeated start (slave keeps SCL low)
278	        if I2cScl_Sync = '0' and r.CmdTypeLatch = CMD_REPSTART then
279	          v.QuartPeriodCnt := (others => '0');
280	        end if;
281	
282	        -- Handle Arbitration (other master transmits start condition first)
283	        if I2cSda_Sync = '0' then
284	          v.Fsm := ArbitLost_s;
285	        end if;
286	
287	        v.SclOut := '1';
288	        v.SdaOut := '1';
289	
290	      when Start2_s =>
291	        if r.QPeriodTick = '1' then
292	          v.Fsm       := WaitCmd_s;
293	          v.rsp_vld_o := '1';
294	        end if;
295	        v.SclOut := '1';
296	        v.SdaOut := '0';
297	
298	      -- **********************************************************************************************
299	      -- Wait for user command (in first half of SCL low phase)
300	      -- **********************************************************************************************
301	      when WaitCmd_s =>
302	        -- Default Outputs
303	        v.cmd_rdy_o := '1';
304	        v.SclOut    := '0';
305	
306	        -- All commands except START are allowed, START commands are ignored
307	        if (r.cmd_rdy_o = '1') and (cmd_vld_i = '1') then
308	          assert (cmd_type_i = CMD_STOP) or (cmd_type_i = CMD_REPSTART) or (cmd_type_i = CMD_SEND) or (cmd_type_i = CMD_REC) or disable_asserts_g
309	          report "###ERROR###: psi_common_i2c_master: In WaitCmd_s state, CMD_START commands are not allowed!"
310	          severity error;
311	          if (cmd_type_i = CMD_STOP) or (cmd_type_i = CMD_REPSTART) or (cmd_type_i = CMD_SEND) or (cmd_type_i = CMD_REC) then
312	            v.Fsm       := WaitLowCenter_s;
313	            v.cmd_rdy_o := '0';
314	          else
315	            v.rsp_vld_o := '1';
316	            v.rsp_seq_o := '1';
317	          end if;
318	          -- Latch data (used for SEND)
319	          v.ShReg := cmd_dat_i & '0';
320	        -- Command timeout - In this case send a STOP to free the bus
321	        elsif r.CmdTimeout = '1' then
322	          v.Fsm           := WaitLowCenter_s;
323	          v.cmd_rdy_o     := '0';
324	          v.timeout_cmd_o := '1';
325	        end if;
326	
327	      -- **********************************************************************************************
328	      -- Wait for center of SCL low phase (after user command arrived)
329	      -- **********************************************************************************************
330	      when WaitLowCenter_s =>
331	        -- State Handling
332	        v.SclOut := '0';
333	        v.BitCnt := (others => '0');
334	
335	        -- Switch to commands
336	        if r.QPeriodTick = '1' then
337	          -- In timeout case, send a STOP to free the bus
338	          if r.CmdTimeout = '1' then
339	            v.Fsm := Stop1_s;
340	          -- Else, go to requested command
341	          else
342	            case r.CmdTypeLatch is
343	              when CMD_STOP     => v.Fsm := Stop1_s;
344	              when CMD_REPSTART => v.Fsm := RepStart1_s;
345	              when CMD_SEND     => v.Fsm := DataBit1_s;
346	              when CMD_REC      => v.Fsm := DataBit1_s;
347	              when others       => null;
348	            end case;
349	          end if;
350	        end if;
351	
352	      -- **********************************************************************************************
353	      -- Start Condition
354	      -- **********************************************************************************************
355	      -- State	   RepStart1_s   Start1_s   Start2_s   WaitCmd_s
356	      --                          _____________________
357	      -- Scl ..._________________|                     |___________ ...
358	      --           __________________________
359	      -- SDA ...XXX                          |_____________________ ...
360	      -- **********************************************************************************************
361	      -- States after RepStart1_s are shared with normal start condition
362	
363	      when RepStart1_s =>
364	        if r.QPeriodTick = '1' then
365	          -- The rest of the sequence is same as for START
366	          v.Fsm := Start1_s;
367	
368	          -- Handle Arbitration other master prvents repeating start by transmitting 0
369	          if I2cSda_Sync = '0' then
370	            v.Fsm := ArbitLost_s;
371	          end if;
372	        end if;
373	        v.SclOut := '0';
374	        v.SdaOut := '1';
375	
376	      -- **********************************************************************************************
377	      -- Start Condition
378	      -- **********************************************************************************************
379	      -- State  DataBit1_s   DataBit2_s   DataBit3_s   WaitCmd_s / DataBit4_s
380	      --                    _________________________
381	      -- Scl ...___________|                         |___________ ...
382	      --
383	      -- SDA ...XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX
384	      -- **********************************************************************************************
385	      -- The DataBit1_s is the second half of the SCL low period. So the
386	      -- SDA Line is set at the beginning of DataBit1_s. After the SCL high period
387	      -- of the last bit, the state is changed to WaitCmd_s. Otherwise the first half of the SCL low
388	      -- period is executed (DataBit4_s) before the next bit starts (DataBit1_s)
389	
390	      when DataBit1_s =>
391	        if r.QPeriodTick = '1' then
392	          v.Fsm := DataBit2_s;
393	        end if;
394	        v.SclOut := '0';
395	
396	        -- Send Operation
397	        if r.CmdTypeLatch = CMD_SEND then
398	          -- For Ack, receive data
399	          if r.BitCnt = 8 then
400	            v.SdaOut := '1';
401	          -- .. else send data
402	          else
403	            v.SdaOut := r.ShReg(8);
404	          end if;
405	        -- Receive Operatiom
406	        else
407	          -- Ack Handling
408	          if r.BitCnt = 8 then
409	            if r.CmdAckLatch = '1' then
410	              v.SdaOut := '0';
411	            else
412	              v.SdaOut := '1';
413	            end if;
414	          -- .. else tri-state for receiving
415	          else
416	            v.SdaOut := '1';
417	          end if;
418	        end if;
419	
420	      when DataBit2_s =>
421	        if r.QPeriodTick = '1' then
422	          v.Fsm   := DataBit3_s;
423	          -- Shift register in the middle of the CLK pulse
424	          v.ShReg := r.ShReg(7 downto 0) & I2cSda_Sync;
425	        end if;
426	        v.SclOut := '1';
427	
428	        -- Handle Clock Stretching (slave keeps SCL low)
429	        if I2cScl_Sync = '0' then
430	          v.QuartPeriodCnt := (others => '0');
431	        end if;
432	
433	        -- Handle Arbitration for Sending (only databits, not ack)
434	        if (r.CmdTypeLatch = CMD_SEND) and (r.BitCnt /= 8) then
435	          if I2cSda_Sync /= r.SdaOut then
436	            v.Fsm := ArbitLost_s;
437	          end if;
438	          -- Receiving does not need arbitration since slave addresses are unique
439	        end if;
440	
441	      when DataBit3_s =>
442	        if r.QPeriodTick = '1' then
443	          -- Command Done after 9 bits (8 Data + 1 Ack)
444	          if r.BitCnt = 8 then
445	            v.Fsm       := WaitCmd_s;
446	            v.rsp_vld_o := '1';
447	          -- Else goto next bit
448	          else
449	            v.Fsm := DataBit4_s;
450	          end if;
451	        end if;
452	        v.SclOut := '1';
453	
454	        -- Handle Arbitration for Sending (only databits, not ack)
455	        if (r.CmdTypeLatch = CMD_SEND) and (r.BitCnt /= 8) then
456	          if I2cSda_Sync /= r.SdaOut then
457	            v.Fsm := ArbitLost_s;
458	          end if;
459	          -- Receiving does not need arbitration since slave addresses are unique
460	        end if;
461	
462	      when DataBit4_s =>
463	        if r.QPeriodTick = '1' then
464	          v.Fsm    := DataBit1_s;
465	          v.BitCnt := r.BitCnt + 1;
466	        end if;
467	        v.SclOut := '0';
468	
469	      -- **********************************************************************************************
470	      -- Stop Condition
471	      -- **********************************************************************************************
472	      -- State   WaitCmd_s   Stop1_s   Stop2_s   Stop3_s   BusIdle_s
473	      --                              _____________________
474	      -- Scl ..._____________________|                     |__________ ...
475	      --                                         _____________________
476	      -- SDA ...XXXXXXXXXXXX____________________|                      ...
477	      -- **********************************************************************************************
478	
479	      when Stop1_s =>
480	        if r.QPeriodTick = '1' then
481	          v.Fsm := Stop2_s;
482	        end if;
483	        v.SclOut := '0';
484	        v.SdaOut := '0';
485	
486	      when Stop2_s =>
487	        if r.QPeriodTick = '1' then
488	          v.Fsm := Stop3_s;
489	        end if;
490	        v.SclOut := '1';
491	        v.SdaOut := '0';
492	
493	        -- Handle Clock Stretching (slave keeps SCL low)
494	        if I2cScl_Sync = '0' then
495	          v.QuartPeriodCnt := (others => '0');
496	        end if;
497	
498	      when Stop3_s =>
499	        if r.QPeriodTick = '1' then
500	          -- Handle Arbitration
501	          if I2cSda_Sync = '0' then
502	            v.Fsm := ArbitLost_s;
503	          -- Else the STOP was successful
504	          else
505	            v.Fsm       := BusIdle_s;
506	            v.rsp_vld_o := '1';
507	          end if;
508	        end if;
509	        v.SclOut := '1';
510	        v.SdaOut := '1';
511	
512	      -- **********************************************************************************************
513	      --  Send Response in case the arbitration was lost
514	      -- **********************************************************************************************
515	
516	      when ArbitLost_s =>
517	        v.Fsm            := BusBusy_s;
518	        v.rsp_vld_o      := '1';
519	        v.rsp_ack_o      := '0';
520	        v.rsp_arb_lost_o := '1';
521	        v.SclOut         := '1';
522	        v.SdaOut         := '1';
523	
524	      when others => null;
525	    end case;
526	
527	    -- TODO: FSM Stuck detection timeout!
528	
529	    -- *** Bus Busy ***
530	    if r.Fsm = BusIdle_s then
531	      v.bus_busy_o := '0';
532	    else
533	      v.bus_busy_o := '1';
534	    end if;
535	
536	    -- *** assign signal ***
537	    r_next <= v;
538	  end process;
539	
540	  --------------------------------------------------------------------------
541	  -- Outputs
542	  --------------------------------------------------------------------------
543	  bus_busy_o     <= r.bus_busy_o;
544	  cmd_rdy_o      <= r.cmd_rdy_o;
545	  rsp_vld_o      <= r.rsp_vld_o;
546	  rsp_type_o     <= r.CmdTypeLatch;
547	  rsp_arb_lost_o <= r.rsp_arb_lost_o;
548	  rsp_ack_o      <= r.rsp_ack_o;
549	  rsp_dat_o      <= r.rsp_dat_o;
550	  rsp_seq_o      <= r.rsp_seq_o;
551	  timeout_cmd_o  <= r.timeout_cmd_o;
552	  g_intTristate : if internal_tri_state_g generate
553	    i2c_scl_io <= 'Z' when r.SclOut = '1' else '0';
554	    i2c_sda_io <= 'Z' when r.SdaOut = '1' else '0';
555	    i2c_scl_o  <= '0';
556	    i2c_sda_o  <= '0';
557	    i2c_scl_t  <= '1';
558	    i2c_sda_t  <= '1';
559	  end generate;
560	  g_extTristatte : if not internal_tri_state_g generate
561	    i2c_scl_o  <= r.SclOut;
562	    i2c_sda_o  <= r.SdaOut;
563	    i2c_scl_t  <= r.SclOut;
564	    i2c_sda_t  <= r.SdaOut;
565	    i2c_scl_io <= 'Z';
566	    i2c_sda_io <= 'Z';
567	  end generate;
568	
569	  --------------------------------------------------------------------------
570	  -- Sequential Proccess
571	  --------------------------------------------------------------------------
572	  p_seq : process(clk_i)
573	  begin
574	    if rising_edge(clk_i) then
575	      r <= r_next;
576	      if rst_i = rst_pol_g then
577	        r.bus_busy_o   <= '0';
578	        r.cmd_rdy_o    <= '0';
579	        r.SclLast      <= '1';
580	        r.SdaLast      <= '1';
581	        r.BusBusyToCnt <= (others => '0');
582	        r.Fsm          <= BusIdle_s;
583	        r.SclOut       <= '1';
584	        r.SdaOut       <= '1';
585	        r.rsp_vld_o    <= '0';
586	      end if;
587	    end if;
588	  end process;
589	
590	  --------------------------------------------------------------------------
591	  -- Component Instantiations
592	  --------------------------------------------------------------------------
593	  I2cScl_Input <= to_01X(i2c_scl_io) when internal_tri_state_g else i2c_scl_i;
594	  I2cSda_Input <= to_01X(i2c_sda_io) when internal_tri_state_g else i2c_sda_i;
595	
596	  i_sync : entity work.psi_common_bit_cc
597	    generic map(
598	      width_g => 2
599	    )
600	    port map(
601	      dat_i(0) => I2cScl_Input,
602	      dat_i(1) => I2cSda_Input,
603	      clk_i    => clk_i,
604	      dat_o(0) => I2cScl_Sync,
605	      dat_o(1) => I2cSda_Sync
606	    );
607	
608	end architecture;

