39	------------------------------------------------------------
40	-- Architecture
41	------------------------------------------------------------
42	architecture sim of psi_common_i2c_master_tb is
43	  -- *** Fixed Generics ***
44	  constant clock_frequency_g : real := 125.0e6;
45	  constant i2c_frequency_g   : real := 1.0e6;
46	  constant bus_busy_timeout_g : real := 50.0e-6;
47	  constant cmd_timeout_g     : real := 10.0e-6;
48	
49	  -- *** Not Assigned Generics (default values) ***
50	
51	  -- *** TB Control ***
52	  signal TbRunning            : boolean                  := True;
53	  signal NextCase             : integer                  := -1;
54	  signal ProcessDone          : std_logic_vector(0 to 1) := (others => '0');
55	  constant AllProcessesDone_c : std_logic_vector(0 to 1) := (others => '1');
56	  constant TbProcNr_stim_c    : integer                  := 0;
57	  constant TbProcNr_i2c_c     : integer                  := 1;
58	  signal StimCase             : integer                  := -1;
59	  signal I2cCase              : integer                  := -1;
60	
61	  -- *** DUT Signals ***
62	  signal clk_i        : std_logic                    := '1';
63	  signal rst_i        : std_logic                    := '1';
64	  signal cmd_rdy_o     : std_logic                    := '0';
65	  signal cmd_vld_i     : std_logic                    := '0';
66	  signal cmd_type_i    : std_logic_vector(2 downto 0) := (others => '0');
67	  signal cmd_dat_i    : std_logic_vector(7 downto 0) := (others => '0');
68	  signal cmd_ack_i     : std_logic                    := '0';
69	  signal rsp_vld_o     : std_logic                    := '0';
70	  signal rsp_dat_o    : std_logic_vector(7 downto 0) := (others => '0');
71	  signal rsp_type_o    : std_logic_vector(2 downto 0) := (others => '0');
72	  signal rsp_arb_lost_o : std_logic                    := '0';
73	  signal rsp_ack_o     : std_logic                    := '0';
74	  signal rsp_seq_o     : std_logic                    := '0';
75	  signal bus_busy_o    : std_logic                    := '0';
76	  signal timeout_cmd_o : std_logic                    := '0';
77	  signal i2c_scl_io     : std_logic                    := '0';
78	  signal i2c_sda_io     : std_logic                    := '0';
79	  signal i2c_scl_i   : std_logic                    := '0';
80	  signal i2c_scl_o   : std_logic                    := '0';
81	  signal i2c_scl_t   : std_logic                    := '0';
82	  signal i2c_sda_i   : std_logic                    := '0';
83	  signal i2c_sda_o   : std_logic                    := '0';
84	  signal i2c_sda_t   : std_logic                    := '0';
85	
86	  -- *** Helper Functions ***
87	  procedure WaitForCase(signal TestCase : in integer;
88	                        Value           : in integer) is
89	  begin
90	    if TestCase /= Value then
91	      wait until TestCase = Value;
92	    end if;
93	  end procedure;
94	
95	  procedure ApplyCmd(Command        : in std_logic_vector(2 downto 0);
96	                     Data           : in std_logic_vector(7 downto 0);
97	                     Ack            : in std_logic;
98	                     signal cmd_vld_i  : out std_logic;
99	                     signal cmd_rdy_o  : in std_logic;
100	                     signal cmd_type_i : out std_logic_vector(2 downto 0);
101	                     signal cmd_dat_i : out std_logic_vector(7 downto 0);
102	                     signal cmd_ack_i  : out std_logic) is
103	  begin
104	    wait until rising_edge(clk_i);
105	    cmd_vld_i  <= '1';
106	    cmd_type_i <= Command;
107	    cmd_dat_i <= Data;
108	    cmd_ack_i  <= Ack;
109	    wait until rising_edge(clk_i) and cmd_rdy_o = '1';
110	    cmd_vld_i  <= '0';
111	    cmd_type_i <= (others => '0');
112	    cmd_dat_i <= (others => '0');
113	    cmd_ack_i  <= '0';
114	  end procedure;
115	
116	  procedure CheckRsp(Command           : in std_logic_vector(2 downto 0);
117	                     Data              : in std_logic_vector;
118	                     Ack               : in std_logic;
119	                     ArbLost           : in std_logic;
120	                     signal rsp_vld_o     : in std_logic;
121	                     signal rsp_dat_o    : in std_logic_vector(7 downto 0);
122	                     signal rsp_type_o    : in std_logic_vector(2 downto 0);
123	                     signal rsp_arb_lost_o : in std_logic;
124	                     signal rsp_ack_o     : in std_logic;
125	                     signal rsp_seq_o     : in std_logic;
126	                     Msg               : in string    := "No Msg";
127	                     Err               : in std_logic := '0') is
128	  begin
129	    wait until rising_edge(clk_i) and rsp_vld_o = '1';
130	    StdlvCompareStdlv(Command, rsp_type_o, "Response: Wrong Type - " & Msg);
131	    if Data /= "X" then
132	      StdlvCompareStdlv(Data, rsp_dat_o, "Response: Wrong Data - " & Msg);
133	    end if;
134	    if Ack /= 'X' then
135	      StdlCompare(choose(Ack = '1', 1, 0), rsp_ack_o, "Response: Wrong Ack - " & Msg);
136	    end if;
137	    if ArbLost /= 'X' then
138	      StdlCompare(choose(ArbLost = '1', 1, 0), rsp_arb_lost_o, "Response: Wrong ArbLost - " & Msg);
139	    end if;
140	    StdlCompare(choose(Err = '1', 1, 0), rsp_seq_o, "Response: Wrong Err - " & Msg);
141	  end procedure;
142	
143	begin
144	  ------------------------------------------------------------
145	  -- DUT Instantiation
146	  ------------------------------------------------------------
147	  i_dut : entity work.psi_common_i2c_master
148	    generic map(
149	      clock_frequency_g   => clock_frequency_g,
150	      i2c_frequency_g     => i2c_frequency_g,
151	      bus_busy_timeout_g   => bus_busy_timeout_g,
152	      cmd_timeout_g       => cmd_timeout_g,
153	      internal_tri_state_g => internal_tri_state_g,
154	      disable_asserts_g   => true
155	    )
156	    port map(
157	      clk_i        => clk_i,
158	      rst_i        => rst_i,
159	      cmd_rdy_o     => cmd_rdy_o,
160	      cmd_vld_i     => cmd_vld_i,
161	      cmd_type_i    => cmd_type_i,
162	      cmd_dat_i    => cmd_dat_i,
163	      cmd_ack_i     => cmd_ack_i,
164	      rsp_vld_o     => rsp_vld_o,
165	      rsp_type_o    => rsp_type_o,
166	      rsp_arb_lost_o => rsp_arb_lost_o,
167	      rsp_dat_o    => rsp_dat_o,
168	      rsp_ack_o     => rsp_ack_o,
169	      rsp_seq_o     => rsp_seq_o,
170	      bus_busy_o    => bus_busy_o,
171	      timeout_cmd_o => timeout_cmd_o,
172	      i2c_scl_io     => i2c_scl_io,
173	      i2c_sda_io     => i2c_sda_io,
174	      i2c_scl_i   => i2c_scl_i,
175	      i2c_scl_o   => i2c_scl_o,
176	      i2c_scl_t   => i2c_scl_t,
177	      i2c_sda_i   => i2c_sda_i,
178	      i2c_sda_o   => i2c_sda_o,
179	      i2c_sda_t   => i2c_sda_t
180	    );
181	
182	  ------------------------------------------------------------
183	  -- I2C Emulation
184	  ------------------------------------------------------------		
185	  I2cPullup(i2c_scl_io, i2c_sda_io);
186	  g_triState : if not internal_tri_state_g generate
187	    i2c_scl_io   <= 'Z' when i2c_scl_t = '1' else i2c_scl_o;
188	    i2c_scl_i <= to_01X(i2c_scl_io);
189	    i2c_sda_io   <= 'Z' when i2c_sda_t = '1' else i2c_sda_o;
190	    i2c_sda_i <= to_01X(i2c_sda_io);
191	  end generate;
192	
193	  ------------------------------------------------------------
194	  -- Testbench Control !DO NOT EDIT!
195	  ------------------------------------------------------------
196	  p_tb_control : process
197	  begin
198	    wait until rst_i = '0';
199	    wait until ProcessDone = AllProcessesDone_c;
200	    TbRunning <= false;
201	    wait;
202	  end process;
203	
204	  ------------------------------------------------------------
205	  -- Clocks !DO NOT EDIT!
206	  ------------------------------------------------------------
207	  p_clock_Clk : process
208	    constant Frequency_c : real := real(125e6);
209	  begin
210	    while TbRunning loop
211	      wait for 0.5 * (1 sec) / Frequency_c;
212	      clk_i <= not clk_i;
213	    end loop;
214	    wait;
215	  end process;
216	
217	  ------------------------------------------------------------
218	  -- Resets
219	  ------------------------------------------------------------
220	  p_rst_Rst : process
221	  begin
222	    wait for 1 us;
223	    -- Wait for two clk edges to ensure reset is active for at least one edge
224	    wait until rising_edge(clk_i);
225	    wait until rising_edge(clk_i);
226	    rst_i <= '0';
227	    wait;
228	  end process;
229	
230	  ------------------------------------------------------------
231	  -- Processes
232	  ------------------------------------------------------------
233	  -- *** stim ***
234	  p_stim : process
235	  begin
236	    I2cSetFrequency(i2c_frequency_g);
237	    -- start of process !DO NOT EDIT
238	    wait until rst_i = '0';
239	    wait until rising_edge(clk_i);
240	
241	    -- *** Test Bus Busy ***
242	    print(">> Test Bus Busy");
243	    StimCase <= 0;
244	    wait until rising_edge(clk_i);
245	    WaitForCase(I2cCase, 0);
246	    wait for 10 us;
247	
248	    -- *** Test Start / Repeated-Start / Stop ***
249	    print(">> Test Start / Repeated-Start / Stop");
250	    StimCase <= 1;
251	    wait until rising_edge(clk_i);
252	    ApplyCmd(CMD_START, X"00", 'X', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
253	    CheckRsp(CMD_START, "X", 'X', '0', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Start");
254	    ApplyCmd(CMD_REPSTART, X"00", 'X', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
255	    CheckRsp(CMD_REPSTART, "X", 'X', '0', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Start");
256	    ApplyCmd(CMD_STOP, X"00", 'X', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
257	    CheckRsp(CMD_STOP, "X", 'X', '0', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Stop");
258	    WaitForCase(I2cCase, 1);
259	    wait for 10 us;
260	
261	    -- *** Test Write ***
262	    print(">> Test Write");
263	    StimCase <= 2;
264	    wait until rising_edge(clk_i);
265	
266	    -- 1Byte ACK
267	    ApplyCmd(CMD_START, X"00", 'X', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
268	    CheckRsp(CMD_START, "X", 'X', 'X', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Start 1b ACK");
269	    ApplyCmd(CMD_SEND, X"A3", 'X', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
270	    CheckRsp(CMD_SEND, "X", '1', '0', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Start 1b ACK");
271	    ApplyCmd(CMD_STOP, X"00", 'X', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
272	    CheckRsp(CMD_STOP, "X", 'X', 'X', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Stop 1b ACK");
273	
274	    -- 2Byte ACK, then NACK
275	    ApplyCmd(CMD_START, X"00", 'X', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
276	    CheckRsp(CMD_START, "X", 'X', 'X', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Start 2b ACK -> NACK");
277	    ApplyCmd(CMD_SEND, X"12", 'X', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
278	    CheckRsp(CMD_SEND, "X", '1', '0', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Start 2b ACK -> NACK 1");
279	    ApplyCmd(CMD_SEND, X"34", 'X', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
280	    CheckRsp(CMD_SEND, "X", '0', '0', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Start 2b ACK -> NACK 2");
281	    ApplyCmd(CMD_STOP, X"00", 'X', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
282	    CheckRsp(CMD_STOP, "X", 'X', 'X', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Stop 2b ACK -> NACK");
283	
284	    WaitForCase(I2cCase, 2);
285	    wait for 10 us;
286	
287	    -- *** Test Read ***
288	    print(">> Test Read");
289	    StimCase <= 3;
290	    wait until rising_edge(clk_i);
291	
292	    -- 1Byte ACK
293	    ApplyCmd(CMD_START, X"00", 'X', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
294	    CheckRsp(CMD_START, "X", 'X', 'X', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Start 1b ACK");
295	    ApplyCmd(CMD_REC, X"00", '1', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
296	    CheckRsp(CMD_REC, X"67", '1', '0', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Start 1b ACK");
297	    ApplyCmd(CMD_STOP, X"00", 'X', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
298	    CheckRsp(CMD_STOP, "X", 'X', 'X', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Stop 1b ACK");
299	
300	    -- 2Byte ACK, then NACK
301	    ApplyCmd(CMD_START, X"00", 'X', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
302	    CheckRsp(CMD_START, "X", 'X', 'X', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Start 2b ACK -> NACK");
303	    ApplyCmd(CMD_REC, X"00", '1', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
304	    CheckRsp(CMD_REC, X"34", 'X', '0', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Start 2b ACK -> NACK 1");
305	    ApplyCmd(CMD_REC, X"00", '0', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
306	    CheckRsp(CMD_REC, X"56", 'X', '0', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Start 2b ACK -> NACK 2");
307	    ApplyCmd(CMD_STOP, X"00", 'X', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
308	    CheckRsp(CMD_STOP, "X", 'X', 'X', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Stop 2b ACK -> NACK");
309	
310	    WaitForCase(I2cCase, 3);
311	    wait for 10 us;
312	
313	    -- *** Test Clock Stretching ***
314	    print(">> Test Clock Stretching");
315	    StimCase <= 4;
316	    wait until rising_edge(clk_i);
317	
318	    -- 1Byte Read ACK
319	    ApplyCmd(CMD_START, X"00", 'X', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
320	    CheckRsp(CMD_START, "X", 'X', 'X', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Start Read 1b ACK");
321	    ApplyCmd(CMD_REC, X"00", '1', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
322	    CheckRsp(CMD_REC, X"67", '1', '0', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Start Read 1b ACK");
323	    ApplyCmd(CMD_STOP, X"00", 'X', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
324	    CheckRsp(CMD_STOP, "X", 'X', 'X', rsp_vld_o, rsp_dat_o, rsp_type_o, rsp_arb_lost_o, rsp_ack_o, rsp_seq_o, "Stop Read 1b ACK");
325	
326	    -- 2Byte ACK, then NACK
327	    ApplyCmd(CMD_START, X"00", 'X', cmd_vld_i, cmd_rdy_o, cmd_type_i, cmd_dat_i, cmd_ack_i);
