592	    I2cSlaveExpectByte(16#12#, i2c_scl_io, i2c_sda_io, "S: Data Lost RepStartA 2", '0');
593	    I2cSlaveWaitStop(i2c_scl_io, i2c_sda_io, "S: Stop Lost RepStartA");
594	
595	    -- Arbitration Lost during repeated start (other master stops)
596	    I2cSlaveWaitStart(i2c_scl_io, i2c_sda_io, "S: Start Lost RepStartB");
597	    I2cSlaveExpectByte(16#A3#, i2c_scl_io, i2c_sda_io, "S: Data Lost RepStartB 1", '0');
598	    I2cSlaveWaitStop(i2c_scl_io, i2c_sda_io, "S: Stop Lost RepStartB");
599	
600	    -- Arbitration lost due to stop (during first bit of data)
601	    I2cSlaveWaitStart(i2c_scl_io, i2c_sda_io, "S: Start Lost DueStop");
602	    I2cSlaveExpectByte(16#A3#, i2c_scl_io, i2c_sda_io, "S: Data Lost DueStop 1", '0');
603	    I2cSlaveWaitStop(i2c_scl_io, i2c_sda_io, "S: Stop Lost DueStop");
604	
605	    -- Arbitration lost due to rep-start (during first bit of data)
606	    I2cSlaveWaitStart(i2c_scl_io, i2c_sda_io, "S: Start Lost RepStart");
607	    I2cSlaveExpectByte(16#A3#, i2c_scl_io, i2c_sda_io, "S: Write Lost RepStart 1", '0');
608	    I2cSlaveWaitRepeatedStart(i2c_scl_io, i2c_sda_io, "S: Lost RepStart RepStart");
609	    I2cSlaveSendByte(16#34#, i2c_scl_io, i2c_sda_io, "S: Read Lost RepStart RepStart", '0');
610	    I2cSlaveWaitStop(i2c_scl_io, i2c_sda_io, "S: Stop Lost RepStart");
611	
612	    I2cCase <= 6;
613	
614	    -- end of process !DO NOT EDIT!
615	    ProcessDone(TbProcNr_i2c_c) <= '1';
616	    wait;
617	  end process;
618	
619	  -- *** i2c master ***
620	  p_i2c_master : process
621	  begin
622	    I2cBusFree(i2c_scl_io, i2c_sda_io);
623	
624	    -- *** Test Arbitration ***
625	    WaitForCase(StimCase, 6);
626	
627	    -- Multi Master, Same Write 
628	    I2cSlaveWaitStart(i2c_scl_io, i2c_sda_io, "M: Start 1b Ack");
629	    -- small delay
630	    i2c_scl_io <= '0';
631	    wait for 100 ns;
632	    -- continue
633	    I2cMasterSendByte(16#A3#, i2c_scl_io, i2c_sda_io, "M: Data 1b Ack");
634	    I2cMasterSendStop(i2c_scl_io, i2c_sda_io, "M: Stop");
635	
636	    -- Arbitration Lost during Write
637	    I2cSlaveWaitStart(i2c_scl_io, i2c_sda_io, "M: Start Lost Write");
638	    I2cMasterSendByte(16#87#, i2c_scl_io, i2c_sda_io, "M: Data Lost Write");
639	    I2cMasterSendStop(i2c_scl_io, i2c_sda_io, "M: Stop Loast Read");
640	
641	    -- Arbitration Lost STOP (other master continues writing)
642	    I2cSlaveWaitStart(i2c_scl_io, i2c_sda_io, "M: Start Lost Stop");
643	    I2cMasterSendByte(16#A3#, i2c_scl_io, i2c_sda_io, "M: Data Lost Stop 1");
644	    I2cMasterSendByte(16#12#, i2c_scl_io, i2c_sda_io, "M: Data Lost Stop 2");
645	    I2cMasterSendStop(i2c_scl_io, i2c_sda_io, "M: Stop Lost Stop");
646	
647	    -- Arbitration Lost during repeated start (other master continues writing)
648	    I2cSlaveWaitStart(i2c_scl_io, i2c_sda_io, "M: Start Lost RepStartA");
649	    I2cMasterSendByte(16#A3#, i2c_scl_io, i2c_sda_io, "M: Data Lost RepStartA 1");
650	    I2cMasterSendByte(16#12#, i2c_scl_io, i2c_sda_io, "M: Data Lost RepStartA 2");
651	    I2cMasterSendStop(i2c_scl_io, i2c_sda_io, "M: Stop Lost RepStartA");
652	
653	    -- Arbitration Lost during repeated start (other master stops)
654	    I2cSlaveWaitStart(i2c_scl_io, i2c_sda_io, "M: Start Lost RepStartB");
655	    I2cMasterSendByte(16#A3#, i2c_scl_io, i2c_sda_io, "M: Data Lost RepStartB 1");
656	    I2cMasterSendStop(i2c_scl_io, i2c_sda_io, "M: Stop Lost RepStartB");
657	
658	    -- Arbitration lost due to stop (during first bit of data)
659	    I2cSlaveWaitStart(i2c_scl_io, i2c_sda_io, "M: Start Lost DueStop");
660	    I2cMasterSendByte(16#A3#, i2c_scl_io, i2c_sda_io, "M: Data Lost DueStop 1");
661	    I2cMasterSendStop(i2c_scl_io, i2c_sda_io, "M: Stop Lost DueStop");
662	
663	    -- Arbitration lost due to rep-start (during first bit of data)
664	    I2cSlaveWaitStart(i2c_scl_io, i2c_sda_io, "M: Start Lost DueRepstart");
665	    I2cMasterSendByte(16#A3#, i2c_scl_io, i2c_sda_io, "M: write Lost DueRepstart 1");
666	    I2cMasterSendRepeatedStart(i2c_scl_io, i2c_sda_io, "M: Stop Lost DueRepstart");
667	    I2cMasterExpectByte(16#34#, i2c_scl_io, i2c_sda_io, "M: read Lost DueRepstart 1");
668	    I2cMasterSendStop(i2c_scl_io, i2c_sda_io, "M: Stop Lost DueRepstart");
669	
670	    wait;
671	
672	  end process;
